VALUES
  ('elementary-10ced7e2-moex-00441', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過某些措施的採行，刺激景氣復甦，帶動經濟成長。下列何者無法 達成刺激景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "取消補貼政策"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00442', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '若世界僅由甲、乙兩國組成，且甲國生產所有商品的效率皆比乙國的水準高。若以機會成本的觀點而言， 下列有關甲、乙兩國生產及貿易的敘述，何者正確？', '["甲國生產所有商品均具絕對利益", "乙國向甲國進口所有產品最有利", "甲國生產所有商品的機會成本低於乙國", "若兩國進行分工，甲、乙兩國的生產可能線會內縮"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00443', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '大學剛畢業的小湘有三個工作機會與繼續升學的道路可選擇，一是月薪2萬5千元的家教老師；另一是 月薪2萬8千元的房屋仲介；以及月薪3萬元的法務助理；若選擇不就業，繼續進入研究所碩士班就讀， 學雜費兩年共需20萬元。依上述資料判斷，在不考慮其他條件的情況下，針對小湘大學畢業後兩年間做 選擇的機會成本之敘述，下列何者正確？', '["若當家教老師，機會成本為67萬2千元", "若選擇當房屋仲介，外顯成本為72萬元", "若選擇就學，外顯成本為72萬元", "若選擇就學，機會成本為92萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00444', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '從塑化劑事件到毒澱粉，食安危機連環爆，連許多老店與大公司的知名產品都因使用有害人體健康的原 料，使消費者人人自危，深怕吃下肚的是黑心商品。許多產品銷售成績一落千丈，對加工食品業的業績 有負面影響。上述事件使消費者對加工食品需求的影響，下列何者正確？', '["預期加工食品價格會下跌，導致其需求曲線左移", "消費者對加工食品的偏好降低，導致其需求曲線左移", "加工食品的互補品價格下跌，導致加工食品的需求曲線右移", "天然食材製品的價格上漲，導致加工食品的需求曲線右移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00445', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '下列何種情況會使目前國產豬肉需求曲線往左移？', '["人口減少", "豬肉價格下降", "出現狂牛症疑慮", "行政院環境保護署嚴格取締養豬場對環境的污染"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00446', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '甲、乙兩國均為已開發國家，甲國某年兩性同酬日為2個月又5天，乙國則為2個月又27天，顯示相較 於甲國，乙國受僱員工中女性要花費更多工作時間才能與男性同酬。根據上述，下列何種敘述或推測最 為可能？', '["乙國的性別職業隔離現象較甲國嚴重", "甲國制定的女性勞動政策較乙國友善", "兩國男性受高等教育的比例較女性多", "甲國的受僱者人均國民所得較乙國高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00447', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '自強在半導體公司（甲）工作，平日擔任該公司的工會（乙）幹部，回到家裡（丙）是兩個孩子的爸爸， 假日時會帶小孩一起到兒福聯盟（丁）擔任志工，該團體是從事特殊際遇兒童保護工作的非營利組織， 關於前文所述，下列有關甲、乙、丙、丁的分析何者正確？', '["甲屬於《人民團體法》的職業團體", "乙屬於志願結社中的正式團體類型", "丙屬於成員間有職掌與編制的正式團體", "丁屬於私人機構獨立經營的「第二部門」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00448', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '我國的《公民投票法》於民國 108 年修正部分條文內容，依據現行規定，下列何項公民投票案可以成為 「全國性公民投票」提案？', '["行政院提出中央政府總預算案", "立法院經司法院核可提出憲法修正案", "總統經行政院院會決議提出所得稅制度改革案", "人民經連署程序提出廢除《電信法》某項條文"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00449', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '某甲在觀看某部戲劇節目時，發現情節中常會出現某家飲食品牌的標誌，劇中主角的相會地點也通常是 此品牌的店家，使人不知不覺對其產生好感。上述現象最適合用下列何項敘述說明之？', '["媒體藉由廠商品牌以提升節目收視率", "媒體的置入性行銷影響觀眾的認知", "媒體的產製過程受到廣告業主的監督", "閱聽人應加強識讀能力以強化自主判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00450', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-112-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '在最小政府的思潮下，最好的政府是管得最少的政府，下列何者為此思潮強調的政府主要任務？', '["照顧無依民眾", "促進經濟高度成長", "確保基本民生資源供給無虞", "提升生活品質與個人成就機會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:46+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "505", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
